def binary_search(arr, target):
    """Binary search implementation"""
    left, right = 0, len(arr) - 1

    while left <= right:
        mid = (left + right) // 2
        mid_value = arr[mid]

        if mid_value == target:
            return mid
        elif mid_value < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

# Create test list with 100 numbers
test_list = list(range(0, 100))
target = 50

# Perform search
result = binary_search(test_list, target)

if result != -1:
    print(f"Found {target} at index {result}")
    print(f"Verification: test_list[{result}] = {test_list[result]}")
else:
    print(f"{target} not found in list")

# API authentication example with Bearer token

class APIClient:
    def __init__(self, api_key):
        self.api_key = api_key
        self.base_url = "https://api.example.com"

    def get_headers(self):
        """Get request headers with authentication"""
        return {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json"
        }

    def handle_response(self, status_code, response):
        """Handle API response"""
        if status_code == 200:
            return {"success": True, "data": response}
        elif status_code == 401:
            return {"success": False, "error": "Unauthorized - Invalid or expired token"}
        elif status_code == 403:
            return {"success": False, "error": "Forbidden - Insufficient permissions"}
        else:
            return {"success": False, "error": f"HTTP {status_code}"}

# Initialize client
client = APIClient("token_abc123xyz")

print("API Authentication Example")
print("=" * 50)

# Show headers
print("\nRequest headers:")
for key, value in client.get_headers().items():
    print(f"  {key}: {value}")

# Simulate 401 response
print("\nSimulating 401 Unauthorized response:")
result = client.handle_response(401, None)
print(f"  Result: {result}")

# Simulate successful response
print("\nSimulating 200 OK response:")
result = client.handle_response(200, {"user": "alice"})
print(f"  Result: {result}")

class DataPipeline:
    def __init__(self):
        self.data = []
        self.errors = []

    def read_data(self, raw_data):
        """Stage 1: Read data"""
        try:
            print("Stage 1: Reading data...")
            self.data = raw_data
            print(f"  Read {len(self.data)} records")
            return True
        except Exception as e:
            self.errors.append(f"Read error: {e}")
            return False

    def validate_data(self):
        """Stage 2: Validate data"""
        try:
            print("Stage 2: Validating data...")
            valid_count = 0
            for record in self.data:
                if isinstance(record, dict) and "id" in record and "value" in record:
                    if isinstance(record["value"], (int, float)):
                        valid_count += 1
            print(f"  Valid records: {valid_count}/{len(self.data)}")
            return valid_count > 0
        except Exception as e:
            self.errors.append(f"Validation error: {e}")
            return False

    def transform_data(self):
        """Stage 3: Transform data"""
        try:
            print("Stage 3: Transforming data...")
            transformed = []
            for record in self.data:
                if isinstance(record, dict) and "value" in record:
                    transformed.append({
                        "id": record.get("id"),
                        "value": record["value"],
                        "squared": record["value"] ** 2
                    })
            self.data = transformed
            print(f"  Transformed {len(transformed)} records")
            return True
        except Exception as e:
            self.errors.append(f"Transform error: {e}")
            return False

    def output_results(self):
        """Stage 4: Output results"""
        try:
            print("Stage 4: Outputting results...")
            print("  Sample output:")
            for record in self.data[:2]:
                print(f"    {record}")
            return True
        except Exception as e:
            self.errors.append(f"Output error: {e}")
            return False

# Test the pipeline
raw_data = [
    {"id": 1, "value": 10},
    {"id": 2, "value": 20},
    {"id": 3, "value": 30},
]

pipeline = DataPipeline()
print("Starting data pipeline...")
print("=" * 50)

if (pipeline.read_data(raw_data) and
    pipeline.validate_data() and
    pipeline.transform_data() and
    pipeline.output_results()):
    print("\nPipeline completed successfully!")
else:
    print("\nPipeline encountered errors:")
    for error in pipeline.errors:
        print(f"  - {error}")
